#include <bits/stdc++.h>
using namespace std;

const int N = 1e5 + 5;
int n, maxn = 0, t = 0, dis[N];
vector<int> tree[N];

void dfs(int u, int f)
{
    for(int v : tree[u])
    {
        if(v == f) continue;
        dis[v] = dis[u] + 1;
        if(dis[v] > dis[t]) t = v;
        dfs(v, u);
    }     
}

int main()
{
    cin >> n;
    for(int i = 1; i < n; i++)
    {
        int u, v;
        cin >> u >> v;
        tree[u].push_back(v);
        tree[v].push_back(u);
    }
    dfs(1, 0);
    dis[t] = 0;
    dfs(t, 0);
    cout << dis[t];
    return 0;
}
